penpot.ui.open("ColorSlurp Importer","https://webdev.kdjfs.de/colorslurp-importer/index.html",{width:400,height:560});penpot.ui.onMessage(r=>{if(r.type==="get-library-colors"){const e=penpot.library.local.colors.map(o=>({name:o.name}));penpot.ui.sendMessage({type:"library-colors",colors:e})}if(r.type==="import-colors"){const{colors:e}=r;for(const o of e){const t=penpot.library.local.createColor();t.name=o.name,t.color=o.hex,t.opacity=o.alpha}penpot.ui.sendMessage({type:"done",count:e.length})}});
